import{j as e}from"./vendor-Dh_dlHsl.js";import{C as t,A as s,N as n,E as i,P as a,W as o}from"./subject-01-thinking-in-agents-BIrOrpH9.js";const k={id:"state-and-memory",title:"State and Memory",description:"How agents remember, forget, and persist knowledge — from in-session state to long-lived project and user memory.",icon:"🧠",colorHex:"#16a34a",difficulty:"intermediate",estimatedHours:10,prerequisites:["agent-runtime"],chapters:[{id:"c1-session-state",title:"In-Session State",description:"What the agent knows right now — conversation history, app state, and derived values.",difficulty:"intermediate",estimatedMinutes:80,sections:[{id:"s1-conversation-history",title:"Conversation History",description:"The agent short-term memory — what just happened in this session.",difficulty:"intermediate",readingMinutes:10},{id:"s2-application-state",title:"Application State",description:"The global mutable state that tracks settings, tasks, and runtime context.",difficulty:"intermediate",readingMinutes:10},{id:"s3-derived-state",title:"Derived State",description:"Computing answers from existing knowledge — selectors and computed values.",difficulty:"intermediate",readingMinutes:10},{id:"s4-side-effects",title:"State Changes and Side Effects",description:"When one change triggers another — reactive state patterns.",difficulty:"intermediate",readingMinutes:12}]},{id:"c2-persistent-memory",title:"Persistent Memory",description:"Knowledge that outlives a single session — project, user, and team memory.",difficulty:"intermediate",estimatedMinutes:100,sections:[{id:"s1-project-memory",title:"Project Memory",description:"Knowledge tied to a specific workspace — conventions, patterns, and context.",difficulty:"intermediate",readingMinutes:10},{id:"s2-user-memory",title:"User Memory",description:"Preferences that follow a person everywhere — personal settings and habits.",difficulty:"intermediate",readingMinutes:10},{id:"s3-team-memory",title:"Team Memory",description:"Shared knowledge across collaborators — conventions that whole teams agree on.",difficulty:"intermediate",readingMinutes:10},{id:"s4-memory-hierarchy",title:"Memory Hierarchy",description:"Which memory wins when they conflict — resolution order and overrides.",difficulty:"advanced",readingMinutes:12},{id:"s5-auto-extracted",title:"Auto-Extracted Memory",description:"Learning from conversations automatically — extracting reusable knowledge.",difficulty:"advanced",readingMinutes:12}]},{id:"c3-sessions",title:"Sessions and Continuity",description:"Tracking conversations over time — identity, transcripts, resumption, and long runs.",difficulty:"intermediate",estimatedMinutes:80,sections:[{id:"s1-session-identity",title:"Session Identity",description:"Tracking a conversation over time — IDs, timestamps, and metadata.",difficulty:"intermediate",readingMinutes:10},{id:"s2-transcripts",title:"Transcripts",description:"Recording everything for replay and debugging — the audit trail.",difficulty:"intermediate",readingMinutes:10},{id:"s3-resuming",title:"Resuming a Session",description:"Rebuilding context from storage — picking up where you left off.",difficulty:"intermediate",readingMinutes:12},{id:"s4-long-running",title:"Long-Running Agents",description:"Maintaining coherence over hours and days — the challenge of continuity.",difficulty:"advanced",readingMinutes:12}]}]};function r(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("p",{children:"Conversation history is the most immediate form of agent memory. It is the sequence of messages exchanged in the current session — the raw record of what was said, asked, and answered. Without it, every turn is the agent's first interaction with the user."}),e.jsx(t,{title:"Conversation History",number:"Concept 6.1",children:"Conversation history is the ordered sequence of user and assistant messages that have occurred in the current session. It gives the agent continuity — the ability to understand references to previous turns, track multi-step requests, and maintain consistent positions without asking the user to re-explain what they already said. History is the foundation of all other session state."}),e.jsx(s,{title:"The Shared Notepad",children:"Two colleagues working on a problem together share a notepad where everything discussed is written down. Either person can glance at the notepad to recall what was agreed, what was tried, and what is still pending. Conversation history is that shared notepad — it makes the collaboration coherent even when the exchange is long and covers many topics."}),e.jsxs("p",{children:["Conversation history serves multiple functions simultaneously. It provides",e.jsx("strong",{children:" reference context"})," (pronouns and implied references resolve correctly), ",e.jsx("strong",{children:"task continuity"})," (the agent knows where a multi-step task is in progress), and ",e.jsx("strong",{children:"consistency enforcement"}),"(the agent does not contradict positions it took earlier). All three functions depend on history remaining accurate and intact."]}),e.jsx(n,{type:"note",title:"History Is Not Infallible",children:"Conversation history records what was said, not what is true. If the user provided incorrect information earlier and the agent accepted it, that misinformation is now in the history. The agent must remain open to corrections that supersede earlier turns, not treat history as ground truth."}),e.jsx(i,{title:"Conversation History Practice",exercises:[{id:"e6-1-1",difficulty:"beginner",question:'A user says "change it to blue" without prior context in the current session. What should the agent do, and why does conversation history matter here?',hint:'Consider what the agent needs to resolve the pronoun "it."',solution:'Without prior context, "it" is unresolvable. The agent should ask: "I want to help — what would you like to change to blue?" If there were prior turns discussing a specific element (a button, a logo, a document), the agent could resolve the reference from history and proceed without asking.'},{id:"e6-1-2",difficulty:"intermediate",question:'A user corrects information they gave earlier: "Actually, my account number is 12345, not 54321 like I said before." How should the agent handle this correction in terms of conversation history?',hint:"Consider which piece of information the agent should act on going forward.",solution:'The agent should acknowledge the correction, update its working understanding, and proceed with the corrected value. It should not protest that the old value is "in the history." When a later turn explicitly supersedes an earlier one, the later turn takes precedence for all subsequent actions.'},{id:"e6-1-3",difficulty:"advanced",question:"In a multi-agent system where a handoff occurs mid-conversation, what aspects of the conversation history must the receiving agent receive to maintain continuity, and what can be safely omitted?",hint:"Think about what the receiving agent needs to serve the user correctly.",solution:"Must transfer: user's stated goal, key facts provided by the user, commitments made by the prior agent, current status of any in-progress tasks, and the most recent few turns for immediate context. Can omit: detailed reasoning steps of the prior agent, verbatim early turns if summarized, and internal tool call/result details unless they contain facts the user referenced."}]})]})}const j=Object.freeze(Object.defineProperty({__proto__:null,default:r},Symbol.toStringTag,{value:"Module"}));function c(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("p",{children:"Beyond the conversation itself, agents operate within a broader application state — the structured data that describes the world outside the chat window. Account records, task queues, document states, and system configurations are all application state that the agent reads from and writes to."}),e.jsx(t,{title:"Application State",number:"Concept 6.2",children:"Application state is the structured, persistent data managed by the system that the agent interacts with through tools. Unlike conversation history (which lives in the context window), application state lives in external systems — databases, APIs, file stores — and must be explicitly fetched or mutated via tool calls. Application state is the real world the agent acts upon."}),e.jsx("p",{children:"The key distinction is mutability and persistence. Conversation history is append-only within a session. Application state can be created, read, updated, and deleted across sessions — changes persist after the conversation ends and affect other users, systems, and future interactions. This asymmetry is why mutations to application state require more caution than additions to conversation history."}),e.jsx(a,{title:"Application State Changes Are Durable",number:"Principle 6.1",children:"Every tool call that modifies application state creates a durable change in the real world. The agent must treat such calls as consequential and irreversible unless an explicit undo mechanism exists. Confirming before mutating, and logging after, are both essential practices for application state management."}),e.jsx(n,{type:"note",title:"State Freshness",children:"Application state fetched at the beginning of a session may become stale during a long conversation. Before taking an action that depends on a previously fetched value, re-fetch it if the session has been active long enough that concurrent changes are plausible. Stale state reads are a common source of agent errors."}),e.jsx(i,{title:"Application State Practice",exercises:[{id:"e6-2-1",difficulty:"beginner",question:"List three examples of application state and three examples of conversation history from a travel booking agent's session. What makes each belong to its category?",hint:"Application state persists after the session; conversation history does not.",solution:`Application state: (1) the user's saved payment methods, (2) an existing booking in the reservation system, (3) the current flight inventory. Conversation history: (1) the user saying "I prefer window seats," (2) the agent's last fare quote, (3) the user asking about baggage fees. The former exist in external systems; the latter exist only in the chat context.`},{id:"e6-2-2",difficulty:"intermediate",question:"An agent cancels a flight booking and books a replacement. Midway through, the payment for the replacement fails. The original booking is already cancelled. Describe the application state problem and how to design against it.",hint:"Think about transactional integrity and rollback.",solution:'The agent created a partially applied state change — the old booking is gone but the new one failed. To design against this: use a transactional pattern where the original is only cancelled after the replacement is confirmed. If the platform does not support transactions, hold the original in a "pending cancel" state until the replacement succeeds. Always communicate ambiguous state to the user immediately.'},{id:"e6-2-3",difficulty:"advanced",question:"How should an agent handle the case where application state fetched via a read tool call conflicts with information the user provided in the conversation? Which source should take precedence, and when?",hint:"Consider the reliability of each source and the type of conflict.",solution:'System data (application state) is typically authoritative for factual records (balances, dates, IDs). User-provided data takes precedence for preferences and intentions. When there is a factual conflict (user claims X, system shows Y), the agent should surface the discrepancy rather than silently choosing: "Your account shows a balance of $200 — you mentioned $400. Would you like me to look into the difference?" This preserves trust and catches both data errors and user mistakes.'}]})]})}const T=Object.freeze(Object.defineProperty({__proto__:null,default:c},Symbol.toStringTag,{value:"Module"}));function d(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("p",{children:"Agents often need to track state that is not directly stored anywhere — it must be computed from what has happened in the session. This derived state is the agent's working understanding: what the user wants, what has been accomplished, what remains, and what constraints are active."}),e.jsx(t,{title:"Derived State",number:"Concept 6.3",children:"Derived state is information that does not exist in conversation history or application state directly, but is inferred by the agent from those sources. Examples include the current progress toward a multi-step goal, the list of user-expressed constraints accumulated across turns, the agent's current hypothesis about user intent, and a running summary of decisions made. Derived state is the agent's active working model of the task."}),e.jsx(s,{title:"The Detective's Case Board",children:"A detective investigating a case has raw evidence (conversation history and application state) and a case board — their working theory of events, key suspects, and open questions. The case board is derived from the evidence but is not the evidence itself. Updating the case board is continuous, and a good detective revises it when new evidence contradicts the current theory."}),e.jsx("p",{children:"Derived state must be actively maintained. As the conversation evolves, earlier inferences may be invalidated — the user may clarify that they did not mean what the agent inferred, or application state changes may alter what was previously assumed. An agent that acts on stale derived state makes confident mistakes."}),e.jsx(o,{title:"Hardened Inferences",children:'Agents can develop "hardened inferences" — derived conclusions that were correct earlier but persist after being invalidated. Once the agent has decided the user wants X, it may interpret all subsequent messages as confirming X even when they do not. Derived state must be treated as a working hypothesis, not a conclusion.'}),e.jsx(i,{title:"Derived State Practice",exercises:[{id:"e6-3-1",difficulty:"beginner",question:"A user is booking a multi-leg trip. Over six turns they mention: no early flights, prefers aisle seats, traveling with a child, and budget under $800. What derived state should the agent be tracking?",hint:"List the constraints and preferences that have accumulated across turns.",solution:"Derived constraint list: (1) departure time: not before approximately 9am, (2) seat preference: aisle, (3) party: adult + child (likely requires adjacent seats), (4) total budget: under $800. The agent should also derive implied constraints: child fare, possible family seating requirements, potential need for adjacent seats on each leg."},{id:"e6-3-2",difficulty:"intermediate",question:`Midway through a task, the user says "actually, I don't care about the timeline anymore, just get the best price." How should this update the agent's derived state?`,hint:"Identify which earlier derived constraints are invalidated.",solution:"This supersedes any previously derived time-related constraints (no early flights, specific departure windows, urgency signals). The optimization target shifts from balancing time and cost to purely minimizing cost. The agent should explicitly acknowledge the change and confirm its new understanding before proceeding, especially if it has already collected options based on the old priority."},{id:"e6-3-3",difficulty:"advanced",question:"Design a derived state management strategy for an agent that must track progress across a 20-step compliance workflow. How does the agent maintain an accurate picture of what is complete, pending, and blocked?",hint:"Think about explicit state tracking versus inference from history.",solution:"Maintain an explicit task registry in the persistent state block: each step has an ID, status (complete/pending/blocked), completion timestamp, and any blocking dependencies. The registry is updated by the agent as a structured mutation after each step completion, not inferred from history. Blocked states include the reason for blocking. This prevents the agent from re-attempting completed steps or skipping blocked ones due to history compression."}]})]})}const A=Object.freeze(Object.defineProperty({__proto__:null,default:d},Symbol.toStringTag,{value:"Module"}));function l(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("p",{children:"When an agent calls a tool that changes the world — sending a message, modifying a database, triggering a workflow — it produces a side effect. Side effects are how agents accomplish real work, and they are also how agents cause real damage when something goes wrong."}),e.jsxs(t,{title:"Side Effects",number:"Concept 6.4",children:["A side effect is any change to state outside the current context window that results from an agent action. Side effects are categorized by their reversibility:",e.jsx("strong",{children:" reversible side effects"})," can be undone (a draft email that is not yet sent), ",e.jsx("strong",{children:"recoverable side effects"})," require effort to undo (a sent email with a recall mechanism), and ",e.jsx("strong",{children:"irreversible side effects"})," cannot be undone (a deleted record without backup, a published post, a completed payment)."]}),e.jsx("p",{children:"The session state of side effects matters beyond the current action. An action taken in this session affects the state seen in future sessions. An email sent cannot be unsent. A customer record modified persists for the next agent that reads it. Side effects accumulate across sessions and form the persistent footprint of the agent's activity."}),e.jsx(a,{title:"Prefer Reversible Actions",number:"Principle 6.2",children:"When multiple paths lead to the same goal, prefer the one with more reversible side effects. Create a draft before sending. Stage a change before committing. Queue a deletion before executing. Reversibility preserves the ability to recover from mistakes — both the agent's and the user's."}),e.jsx(o,{title:"The Compounding Side Effect",children:"In an agentic loop, each irreversible side effect narrows the space of recoverable futures. An agent that takes five irreversible actions in sequence may find itself in a state from which no good outcome is reachable. The further a loop runs without human checkpoints, the harder recovery becomes."}),e.jsx(i,{title:"Side Effects Practice",exercises:[{id:"e6-4-1",difficulty:"beginner",question:"Classify these agent actions as reversible, recoverable, or irreversible: (a) drafting an email, (b) sending an email, (c) posting to a public social media account, (d) moving a file to trash, (e) permanently deleting a file.",hint:"Consider whether the action can be undone and at what cost.",solution:"(a) Reversible — draft discarded with no effect. (b) Recoverable — email recall exists but is unreliable and the recipient may have read it. (c) Recoverable with difficulty — post can be deleted but screenshots may persist. (d) Reversible — file can be restored from trash. (e) Irreversible — no recovery without backup."},{id:"e6-4-2",difficulty:"intermediate",question:'An agent is asked to "clean up old records from the database." Before executing any deletions, what side effect safeguards should it implement?',hint:"Think about confirmation, reversibility, and scope controls.",solution:'Safeguards: (1) Clarify "old" — define a specific age threshold before acting. (2) Show the user a sample of what will be deleted and get explicit confirmation. (3) Archive rather than delete if possible — move records to a cold storage table first. (4) Execute in small batches with a pause for review rather than all at once. (5) Log every deletion with the record ID and timestamp.'},{id:"e6-4-3",difficulty:"advanced",question:"Design a side effect audit log for a financial agent. What fields should each log entry contain, and how should it be used after an incident to reconstruct what happened?",hint:"Consider who needs to read the log and what questions they need to answer.",solution:"Each entry: session ID, user ID, timestamp, tool name, action type (read/write/delete), target resource (table + record ID), input parameters, result status, and a hash of the pre-action state snapshot. After an incident, the log should enable: (1) chronological reconstruction of all state changes, (2) identification of which action caused the problematic state, (3) replay or rollback using the pre-action snapshots. The log should be immutable — no agent action can modify it."}]})]})}const S=Object.freeze(Object.defineProperty({__proto__:null,default:l},Symbol.toStringTag,{value:"Module"}));function h(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("p",{children:"Some knowledge belongs to a specific project — a shared context that all conversations about that project should have access to, regardless of which session is asking. Project memory is the persistent repository for this shared, task-scoped knowledge."}),e.jsx(t,{title:"Project Memory",number:"Concept 6.5",children:"Project memory is a store of persistent facts, decisions, and context scoped to a specific project or task. It accumulates across sessions and is available to any agent or session working on that project. It captures what has been decided, what is in scope, what constraints apply, and what progress has been made — so future sessions do not start from zero."}),e.jsx(s,{title:"The Project Wiki",children:"A software project's internal wiki holds decisions, architecture notes, and conventions accumulated over months of work. Every new developer reads it to get up to speed. An agent working on the same project should have access to the same shared knowledge — not stored in any single conversation's history, but in a durable project-scoped store that any session can read and update."}),e.jsx("p",{children:"Project memory typically contains: the project's stated goal and success criteria, major decisions and their rationale, known constraints and limitations, completed milestones, open questions, and a log of significant actions taken by agents. The structure should be queryable — it grows too large to inject in full into every context window, so retrieval must be selective."}),e.jsx(n,{type:"tip",title:"Decisions Over Discussions",children:'Project memory is most valuable when it captures decisions and their rationale, not the full discussion that led to them. Storing summaries of debates wastes space. Storing "we decided X because of Y" enables any future session to understand and respect the decision without replaying the reasoning.'}),e.jsx(i,{title:"Project Memory Practice",exercises:[{id:"e6-5-1",difficulty:"beginner",question:"A coding agent has been working on a web application across ten sessions. List five categories of information that should be in project memory to help future sessions continue effectively.",hint:"Think about what a new team member joining the project would need to know.",solution:"(1) Tech stack and key architectural decisions with rationale. (2) Completed features and current status. (3) Known bugs and their triage status. (4) Coding conventions and style decisions specific to the project. (5) Outstanding tasks with priority and any blocking dependencies."},{id:"e6-5-2",difficulty:"intermediate",question:"Two agents are working on the same project in parallel. Agent A updates the project memory with a new decision at the same time Agent B reads it. What consistency problem can arise, and how should the memory store handle it?",hint:"Think about concurrent reads and writes to a shared store.",solution:"Agent B may read a stale version and make decisions inconsistent with Agent A's update. The memory store should use versioning or optimistic locking: each write includes the version it is based on, and a conflict is raised if the version has changed since the last read. Conflicts should surface to human oversight rather than being silently overwritten."},{id:"e6-5-3",difficulty:"advanced",question:"A project spans 18 months and the project memory has grown to 500,000 tokens. Describe a strategy for keeping the memory queryable and cost-effective as it scales.",hint:"Consider indexing, tiered storage, and semantic retrieval.",solution:'Archive old decisions into a vector index searchable by semantic similarity. Maintain a "current state" summary of at most 5,000 tokens that is always injected in full. Retrieval is two-stage: the current state summary is always present; on-demand retrieval fetches specific historical records by semantic query. Entries older than a defined threshold are compressed into category summaries. A project timeline remains uncompressed to preserve chronological navigation.'}]})]})}const q=Object.freeze(Object.defineProperty({__proto__:null,default:h},Symbol.toStringTag,{value:"Module"}));function u(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("p",{children:"Users should not have to re-introduce themselves every session. User memory is the persistent store of what an agent has learned about a specific user — their preferences, history, communication style, and recurring needs — enabling continuity and personalization across all of their sessions."}),e.jsx(t,{title:"User Memory",number:"Concept 6.6",children:"User memory is a persistent, per-user store of facts, preferences, and patterns that should persist across sessions. It captures: expressed preferences (how the user likes to communicate, what formats they prefer), factual context (their role, their environment, their constraints), learned patterns (topics they return to frequently, mistakes to avoid), and relationship history (what has been done for them, what was helpful or not)."}),e.jsx("p",{children:"User memory enables a fundamentally different kind of interaction. Without it, every session is a first meeting. With it, the agent can greet a returning user with awareness of what they care about, avoid repeating mistakes, and offer suggestions calibrated to their actual needs rather than generic defaults."}),e.jsx(a,{title:"Memory Must Be Transparent and Correctable",number:"Principle 6.3",children:"Users must be able to know what the agent remembers about them, correct inaccuracies, and request deletion. An agent acting on incorrect user memory is worse than one with no memory — it confidently delivers the wrong thing. Transparency about stored memory is both an ethical requirement and a practical quality control mechanism."}),e.jsx(o,{title:"Memory Can Entrench Errors",children:"If a user's preferences were inferred incorrectly and stored, they persist until corrected. The agent will apply wrong assumptions across all future sessions, and the user may not know why the experience feels off. Build easy correction flows and periodically surface stored preferences for confirmation."}),e.jsx(i,{title:"User Memory Practice",exercises:[{id:"e6-6-1",difficulty:"beginner",question:"What is the difference between a user preference inferred by the agent and one explicitly stated by the user? How should storage treat each differently?",hint:"Consider confidence level and the need for confirmation.",solution:"Explicitly stated preferences are high confidence and can be stored directly. Inferred preferences are lower confidence — derived from behavioral patterns — and should be flagged as inferred, given a lower confidence score, and surfaced for confirmation before being used persistently. Inferred preferences that the user confirms become explicit."},{id:"e6-6-2",difficulty:"intermediate",question:"A user's stored preferences say they prefer concise responses, but in the current session they are asking very detailed follow-up questions suggesting they want more depth. How should the agent resolve this tension?",hint:"Consider session-level behavior versus stored preferences, and when to update.",solution:`The current session's signals take precedence for the current conversation. The agent should shift to more detailed responses without explanation. After a pattern is clear (multiple turns showing the same behavior), the agent can gently surface the observation: "I've noticed you're asking for more detail today — would you like me to update your preferences to include more thorough explanations?" This gives the user control over whether the change is permanent.`},{id:"e6-6-3",difficulty:"advanced",question:"Design a user memory schema that balances personalization value with privacy minimization. What is stored, what is derived at query time, and what is never stored?",hint:"Apply data minimization principles — store only what delivers genuine value.",solution:"Stored: communication preferences (format, length, formality), domain expertise levels per topic, explicit tool or workflow preferences, confirmed facts the user has stated (role, timezone). Derived at query time: specific behavior patterns (queried from session log aggregates, not stored as assertions). Never stored: sensitive personal details not required for service, content of private conversations (only metadata like topic category), anything with no direct personalization use. All stored entries include a creation date and a review-by date after which the user is prompted to confirm or remove them."}]})]})}const C=Object.freeze(Object.defineProperty({__proto__:null,default:u},Symbol.toStringTag,{value:"Module"}));function m(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("p",{children:"Organizations accumulate knowledge that belongs to neither a single user nor a specific project, but to the team or organization as a whole. Team memory is the persistent store of this shared, organizational knowledge — conventions, decisions, patterns, and policies that apply across all projects and users."}),e.jsx(t,{title:"Team Memory",number:"Concept 6.7",children:"Team memory is a persistent, organization-scoped knowledge store that contains information relevant to how the team works, what it has learned, and what conventions it follows. It includes: established workflows and processes, recurring decisions and their justifications, domain expertise accumulated over time, and institutional knowledge that would otherwise live only in individuals' heads."}),e.jsx(s,{title:"The Organizational Brain",children:"When a senior employee with deep institutional knowledge leaves a company, they take knowledge with them that took years to build. Teams that document decisions, processes, and lessons learned retain that knowledge even through personnel changes. Team memory is the agent-accessible version of that organizational brain — a living repository that grows with every session and is available to every agent working with the team."}),e.jsx("p",{children:"Team memory differs from project memory in scope and lifespan. Project memory is temporary — it ends with the project. Team memory is ongoing — it persists indefinitely and applies broadly. It also differs from user memory in that it represents shared conventions rather than individual preferences. When team memory and user memory conflict, the resolution depends on whether the team's convention is a policy or a default."}),e.jsx(n,{type:"note",title:"Memory Governance",children:"Team memory requires governance — a process for deciding what gets added, who can update it, and when entries expire or are reviewed. Without governance, team memory accumulates outdated conventions that the agent applies confidently to situations they no longer fit."}),e.jsx(i,{title:"Team Memory Practice",exercises:[{id:"e6-7-1",difficulty:"beginner",question:"Give three examples of knowledge that belongs in team memory versus project memory versus user memory for a software development team.",hint:"Think about scope: team-wide, project-specific, and individual.",solution:"Team memory: coding style guide, deployment process, incident response runbook. Project memory: this project's architecture decisions, the chosen database schema, open issues. User memory: a developer's preferred IDE, their timezone, their expertise level in specific languages."},{id:"e6-7-2",difficulty:"intermediate",question:`An agent is helping a new team member and draws on team memory to explain a process. The team member says "that's outdated — we stopped doing it that way six months ago." What should happen next?`,hint:"Consider both the immediate response and the memory update.",solution:"Immediately: the agent should acknowledge the correction and update its working understanding for this session. Memory update: the agent should offer to update the team memory entry with the current process, flag the update for review by a team lead, or create a pending update that requires confirmation before committing. The old entry should be archived, not deleted, so the historical record is preserved."},{id:"e6-7-3",difficulty:"advanced",question:"Design an access control model for team memory in an organization with multiple sub-teams. Which memory entries are visible to all, which are scoped to sub-teams, and how do you handle cross-team conflicts?",hint:"Think about hierarchy, inheritance, and override rules.",solution:"Three tiers: (1) Organization-wide: all agents and teams can read; only designated admins can write. (2) Team-scoped: all members of the team can read and write; other teams cannot read by default unless marked shared. (3) Sub-team scoped: same as team-scoped but narrower. For conflicts: organization-wide entries take precedence over team entries for policies. Team entries take precedence for team-specific conventions. Conflicts between peer teams are flagged for human resolution rather than silently resolved."}]})]})}const I=Object.freeze(Object.defineProperty({__proto__:null,default:m},Symbol.toStringTag,{value:"Module"}));function p(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("p",{children:"User memory, project memory, and team memory do not exist in isolation — they interact, overlap, and sometimes conflict. The memory hierarchy defines how these stores relate to each other and how the agent resolves conflicts between them."}),e.jsxs(t,{title:"Memory Hierarchy",number:"Concept 6.8",children:["The memory hierarchy is the structured relationship between different memory scopes. In most systems it has three levels: ",e.jsx("strong",{children:"organizational/team memory"})," (broadest scope, slowest to change, highest authority for policies), ",e.jsx("strong",{children:"project memory"})," (task-specific, medium scope), and ",e.jsx("strong",{children:"user memory"})," (narrowest scope, highest specificity for individual preferences). Each level can override the level above it for preferences, but not for policies."]}),e.jsx("p",{children:"The hierarchy governs retrieval priority as well as conflict resolution. When assembling the context for a session, memory is typically retrieved from all levels and combined. The agent must know which level each piece of information comes from so it can apply the right precedence rules when pieces conflict."}),e.jsx(a,{title:"Policies Override, Preferences Yield",number:"Principle 6.4",children:"Distinguish between policy entries (mandatory rules that apply regardless of individual or project preference) and default entries (starting points that can be overridden). User preferences can override team defaults but cannot override team policies. This distinction should be explicit in the memory schema, not left to inference."}),e.jsx(n,{type:"tip",title:"Hierarchy Transparency",children:`When an agent's behavior is governed by team memory rather than the current conversation, it helps to briefly surface this: "I'm following our team's standard process here — we always do X before Y." This gives users visibility into why the agent is behaving as it is and an opportunity to challenge or override if appropriate.`}),e.jsx(i,{title:"Memory Hierarchy Practice",exercises:[{id:"e6-8-1",difficulty:"beginner",question:"A user prefers responses in bullet points. The project specifies that all deliverables should be in prose format. The organization has no policy on format. Which preference takes precedence for (a) a conversational response and (b) a formal project deliverable?",hint:"Distinguish between conversational style and deliverable format.",solution:"(a) Conversational response: user preference takes precedence — the user is talking to the agent informally, and bullet points serve them better. (b) Formal deliverable: project scope takes precedence — the deliverable is a project artifact, not a personal message, and the project format standard applies."},{id:"e6-8-2",difficulty:"intermediate",question:"An agent retrieves conflicting information from two levels of the memory hierarchy: team memory says to always CC the manager on external emails, but user memory says this particular user has an exemption. How should the agent handle this?",hint:"Determine whether the team entry is a policy or a default.",solution:"If the team memory entry is a policy: the user cannot override it, and the agent should apply it. The exemption claim should be flagged for human review. If the team memory entry is a default: the user-level exemption overrides it and the agent proceeds without CC. The distinction requires the memory schema to explicitly label entries as policy or default. When unlabeled, the agent should ask or escalate rather than guess."},{id:"e6-8-3",difficulty:"advanced",question:"Design a memory assembly strategy for a session where all three memory levels contribute relevant content. How do you avoid context window bloat while ensuring all critical information is present?",hint:"Think about selective retrieval, priority filtering, and compression by level.",solution:"Assembly strategy: (1) Always inject the current state summaries from all three levels (kept small, max 500 tokens each). (2) Use semantic retrieval from each level to fetch only entries relevant to the current session topic. (3) Apply deduplication — if team and project memory say the same thing, keep the more specific (project) version. (4) Label each retrieved entry with its source level so conflict resolution is transparent. (5) Allocate a fixed token budget per level: team 10%, project 20%, user 15%, leaving 55% for conversation and tools."}]})]})}const M=Object.freeze(Object.defineProperty({__proto__:null,default:p},Symbol.toStringTag,{value:"Module"}));function f(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("p",{children:"Requiring users to manually save important facts to memory creates friction and misses information users do not think to save. Auto-extraction is the process of automatically identifying and storing valuable information from conversations without requiring explicit user action."}),e.jsx(t,{title:"Auto-Extracted Memory",number:"Concept 6.9",children:'Auto-extracted memory is information automatically identified and stored during a conversation based on extraction heuristics or model judgment. Extraction triggers include: explicit user statements about preferences or facts ("I always prefer X"), corrections to prior agent behavior, recurring patterns across sessions, and significant decisions or conclusions that should persist. Auto-extraction reduces friction but introduces accuracy and privacy risks that must be managed.'}),e.jsx("p",{children:'Extraction quality matters enormously. Over-extraction floods the memory store with low-value noise that degrades retrieval. Under-extraction misses genuinely useful knowledge. The extraction model must distinguish between incidental statements ("I was just saying that as an example") and genuinely persistent preferences ("I always want responses formatted this way").'}),e.jsx(n,{type:"tip",title:"Confirm Before Committing",children:'High-value auto-extracted entries should be confirmed with the user before permanent storage. A brief end-of-session summary ("I noticed a few things I could remember for next time — should I save these?") makes the process transparent and gives users control. Confirmation also corrects extraction errors before they persist.'}),e.jsx(o,{title:"Auto-Extraction and Privacy",children:"Auto-extraction can silently accumulate sensitive personal information that the user did not consciously choose to share. An offhand mention of a health condition, financial situation, or personal conflict should not automatically become a permanent memory entry. Apply conservative extraction criteria and exclude categories of sensitive data from automatic storage."}),e.jsx(i,{title:"Auto-Extracted Memory Practice",exercises:[{id:"e6-9-1",difficulty:"beginner",question:`A user says "I'm always forgetting to attach files to emails — that's been a problem for me." Should this be auto-extracted to user memory? Why or why not?`,hint:"Consider whether this is actionable and whether it is genuinely persistent.",solution:'Yes, this is a good candidate. It is a self-described persistent pattern ("always"), it is actionable (the agent can proactively remind the user to attach files when composing emails), and it is not sensitive. Extracted entry: "User frequently forgets to attach files to emails — proactively ask about attachments when helping compose emails."'},{id:"e6-9-2",difficulty:"intermediate",question:"Design three extraction rules (if-then format) that would help an agent identify which statements from a conversation are worth storing in user memory.",hint:"Look for signals that distinguish persistent preferences from in-context statements.",solution:'Rule 1: If the user uses frequency words ("always," "never," "usually," "every time") about their own behavior or preferences, extract as a potential preference. Rule 2: If the user corrects the agent and the correction is about a general preference rather than a specific case ("not just this time — I always want..."), extract as a confirmed preference. Rule 3: If the user explicitly expresses frustration about a repeated issue, extract as a pattern to avoid ("user has found X unhelpful").'},{id:"e6-9-3",difficulty:"advanced",question:"An auto-extraction system has been running for six months and the user memory store now contains 800 entries per user, many outdated or contradictory. Design a memory hygiene strategy to restore quality.",hint:"Think about audit, deduplication, staleness, and conflict resolution.",solution:'Hygiene strategy: (1) Deduplication: cluster semantically similar entries and merge them into the most recent or most specific version. (2) Staleness: entries not referenced in any session for 90+ days are flagged as stale and hidden from retrieval pending review. (3) Contradiction resolution: when two entries conflict, surface both to the user in a periodic "memory review" prompt and ask them to confirm the current truth. (4) Confidence decay: entries with no confirmation events have their confidence score decrease over time, reducing their retrieval weight. (5) Category pruning: entries in sensitive categories with no action utility are deleted on a rolling basis.'}]})]})}const P=Object.freeze(Object.defineProperty({__proto__:null,default:f},Symbol.toStringTag,{value:"Module"}));function g(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("p",{children:"Every agent interaction happens within a session — a bounded unit of communication with a defined start and end. Session identity is the set of attributes that uniquely identify a session and determine who is in it, what permissions are active, and what context should be loaded."}),e.jsx(t,{title:"Session Identity",number:"Concept 6.10",children:"Session identity is the bundle of attributes that uniquely define a conversation instance. It includes: a unique session identifier, the authenticated user identity, the operator context (which deployment or product this session belongs to), the session creation time, and the access permissions active for this session. Session identity is established at the start of the conversation and persists throughout."}),e.jsx(s,{title:"The Hotel Check-In",children:"When a guest checks in, they receive a key card encoded with their room number, their access level (standard guest versus VIP), and their checkout date. Every interaction with the hotel's systems — elevator, gym, restaurant — reads that card to determine what is allowed. A session token works the same way: it carries the identity and permissions that govern what the agent may access and do on behalf of this user, in this context, for this duration."}),e.jsxs("p",{children:["Session identity drives two critical functions. First, it enables",e.jsx("strong",{children:" personalization"})," — the right user memory, preferences, and history are loaded for this user. Second, it enforces ",e.jsx("strong",{children:"authorization"}),"— only resources and actions permitted for this user in this operator context are accessible. A session with a corrupted or spoofed identity can violate both personalization and authorization."]}),e.jsx(n,{type:"note",title:"Session vs. Conversation",children:"A session and a conversation are related but distinct. A session is a technical authentication and authorization context. A conversation is the sequence of messages. A single session can contain multiple conversations (if a user starts a new topic without re-authenticating). A single conversation might span multiple sessions (if a user logs out and resumes). Track both identifiers independently."}),e.jsx(i,{title:"Session Identity Practice",exercises:[{id:"e6-10-1",difficulty:"beginner",question:"List the minimum set of attributes a session identity record should contain for a multi-tenant SaaS agent platform. Explain why each attribute is necessary.",hint:"Think about isolation, authorization, and traceability.",solution:"Session ID (unique, for tracing and resumption), User ID (who this session belongs to), Tenant/Operator ID (which deployment — ensures memory and tools are scoped correctly), Authentication timestamp (session freshness for security), Permission set (what this user is allowed to do), Expiration time (when the session must be re-authenticated)."},{id:"e6-10-2",difficulty:"intermediate",question:"A user opens the same agent in two browser tabs simultaneously, creating two active sessions. What problems can arise, and how should the system handle them?",hint:"Consider state conflicts, duplicate actions, and user experience.",solution:"Problems: (1) Both sessions may independently fetch and modify the same application state, causing conflicts. (2) A user action in tab A may be invisible to tab B, leading to duplicate submissions. (3) Conversation history diverges between sessions. Handling: notify the user that multiple sessions are active. For mutating actions, apply an optimistic lock tied to the session that first initiated the action. Offer session consolidation on login."},{id:"e6-10-3",difficulty:"advanced",question:"How should session identity be designed to support auditing? What information must be captured at session creation to enable a complete audit trail of the session's actions months later?",hint:"Think about who needs to read the audit trail and what questions it must answer.",solution:"At session creation, capture and immutably store: session ID, user ID with their role at time of session, operator/tenant ID, authentication method and timestamp, IP address and user agent (for fraud analysis), permission set snapshot (not just a role name — the actual permissions as they were at that moment). During the session, each action is logged against the session ID with its own timestamp. Months later, the audit trail must answer: who did what, with what permissions, on what timeline, authorized by whom."}]})]})}const D=Object.freeze(Object.defineProperty({__proto__:null,default:g},Symbol.toStringTag,{value:"Module"}));function y(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("p",{children:"A transcript is the durable record of a conversation — every message, every tool call, every result, and every decision made during a session. Transcripts serve operations, quality assurance, compliance, and the ability to resume interrupted sessions."}),e.jsx(t,{title:"Session Transcript",number:"Concept 6.11",children:"A session transcript is the complete, ordered, time-stamped record of all events in a session. For an agent session, this includes: user and assistant messages, tool invocations and their results, any injected system messages or context updates, and session metadata (start/end time, session identity). A complete transcript is both a debugging artifact and a compliance record."}),e.jsxs("p",{children:["Transcripts have multiple consumers with different needs. ",e.jsx("strong",{children:"Operations teams"})," need transcripts to diagnose failures and reproduce issues.",e.jsx("strong",{children:"Quality assurance"})," teams use them to evaluate agent performance and identify patterns in incorrect or harmful responses. ",e.jsx("strong",{children:"Compliance teams"})," need them to verify that the agent behaved within policy.",e.jsx("strong",{children:"Users"})," may need them to review what was done on their behalf. A good transcript format serves all of these consumers."]}),e.jsx(a,{title:"Transcripts Are Immutable",number:"Principle 6.5",children:"Transcripts must be immutable once written. An agent that can modify its own transcript could conceal errors, remove evidence of policy violations, or retroactively alter commitments it made. The transcript is the authoritative record; any correction or annotation must be appended as a new entry, not applied as an edit to an existing one."}),e.jsx(n,{type:"note",title:"Transcript Size Management",children:"Long sessions and tool-heavy agents produce very large transcripts. Structure the transcript format to support selective retrieval — indexed by turn number, by event type, and by timestamp — so consumers can query only the portion they need without reading the entire record."}),e.jsx(i,{title:"Transcripts Practice",exercises:[{id:"e6-11-1",difficulty:"beginner",question:"What is the minimum information each transcript entry should contain to make it useful for both operations debugging and compliance review?",hint:"Think about what these two different consumers need from the same record.",solution:"Minimum per entry: event type (user message / assistant message / tool call / tool result / system event), timestamp, session ID, event content, for tool events: tool name + parameters + result + duration. Operations additionally needs: error codes, latency, model version. Compliance additionally needs: policy version active at the time, any policy triggers or overrides applied."},{id:"e6-11-2",difficulty:"intermediate",question:"A user requests a copy of their conversation transcript for their own records. What should and should not be included in the version provided to the user?",hint:"Consider what is the user's information versus what is system-internal.",solution:"Include: all user messages, all assistant messages, tool invocations and results that the user directly requested or that informed the agent's visible responses. Exclude: internal system messages and operator instructions (may contain confidential operator configuration), raw tool errors with system internals, session metadata beyond creation time and user identity."},{id:"e6-11-3",difficulty:"advanced",question:"Design a transcript retention policy for a healthcare agent that handles sensitive medical queries. What retention periods apply, who can access which parts, and when must transcripts be destroyed?",hint:"Consider regulatory requirements, user rights, and purpose limitation.",solution:"Retention: full transcripts retained for 7 years to meet medical record requirements. Access: users access their own transcripts on request. Clinical staff access transcripts for their own patients only. Compliance accesses redacted transcripts for audit purposes. Security accesses metadata only (no content) for incident investigation. Destruction: on user deletion request, anonymize content while retaining metadata for aggregate analysis. After the 7-year period, schedule automatic deletion. Tool call data containing raw medical terminology is separated into a higher-sensitivity tier with shorter access windows."}]})]})}const _=Object.freeze(Object.defineProperty({__proto__:null,default:y},Symbol.toStringTag,{value:"Module"}));function w(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("p",{children:"Not all conversations reach a natural conclusion. Users close browsers, lose connectivity, or simply run out of time mid-task. Resuming a session means restoring enough state that the agent and user can continue as if the interruption did not happen — or at least understand exactly where they left off."}),e.jsx(t,{title:"Session Resumption",number:"Concept 6.12",children:"Session resumption is the process of restoring a prior session's state into a new context window so that work can continue without requiring the user to re-establish context from scratch. A fully resumable session preserves: the conversation history, the task progress, any pending commitments or outstanding questions from the prior session, and the agent's current understanding of the user's goal."}),e.jsx(s,{title:"The Bookmarked Page",children:'A reader who is interrupted mid-chapter places a bookmark and notes where they were in the story. When they return, they flip to the bookmark, read the last paragraph to re-orient, and continue. Session resumption works the same way: the "bookmark" is the saved session state, and the "last paragraph" is a brief summary of where the conversation was when it paused.'}),e.jsx("p",{children:"Effective resumption requires three things: a durable transcript (so the prior session can be reconstructed), a resumption summary (a compact description of pending state that can be injected into the new session's system prompt), and a reconnection protocol (how the agent greets the returning user and confirms what to do next). The resumption summary is the most important — it bridges the gap between sessions at low token cost."}),e.jsx(o,{title:"Stale Pending Actions",children:'When resuming a session hours or days after interruption, pending actions from the prior session may be stale. A task that was "in progress" may have been completed by another means, superseded by events, or become irrelevant. Always validate the state of pending actions before resuming execution — never assume the world is unchanged.'}),e.jsx(i,{title:"Session Resumption Practice",exercises:[{id:"e6-12-1",difficulty:"beginner",question:"A user was in the middle of filing a support ticket when they lost connectivity. When they return the next day, what should the resumption experience look like?",hint:"Think about what the user needs to know and what the agent needs to verify.",solution:'The agent should greet the returning user and summarize where they left off: "Welcome back. Last time we were working on a support ticket about [topic]. You had filled in [X and Y] and we were about to [next step]. Would you like to continue?" The agent should verify the ticket was not already submitted by another route before proceeding.'},{id:"e6-12-2",difficulty:"intermediate",question:"Design a resumption summary format that captures sufficient context for a coding task that was interrupted mid-implementation. What fields must the summary contain?",hint:"Think about what a developer needs to know to continue work seamlessly.",solution:"Fields: (1) Task description: the original goal in one to two sentences. (2) Completed steps: what has been implemented or decided. (3) Current state: where exactly the work stopped and what was being worked on. (4) Pending steps: what remains to be done. (5) Open questions: anything that was unresolved when the session ended. (6) Key decisions: important choices made and their rationale. (7) Blocking issues: any problems that were preventing progress."},{id:"e6-12-3",difficulty:"advanced",question:"A multi-agent workflow involving three specialized agents was interrupted mid-run. Design a resumption strategy that correctly identifies which agent was active, what state each agent holds, and how to safely continue.",hint:"Consider workflow checkpointing and safe restart points.",solution:"Each agent maintains a checkpoint after completing each discrete sub-task. The checkpoint includes: agent ID, task step, output produced, and the inputs received. On resumption: (1) Read the workflow log to find the last successful checkpoint. (2) Identify which agent was active and at what step. (3) Re-validate the inputs to the interrupted step (they may have changed). (4) Resume from the last checkpoint, not from before it — do not re-execute completed steps. (5) If the interrupted step is partially complete, determine whether it is safe to continue or must be restarted. (6) Notify human oversight before resuming any step that had irreversible side effects."}]})]})}const z=Object.freeze(Object.defineProperty({__proto__:null,default:w},Symbol.toStringTag,{value:"Module"}));function v(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("p",{children:"Most agent sessions are short. But some tasks span hours, days, or weeks — research projects, complex implementations, ongoing workflows. Long-running sessions present challenges that short sessions do not: context window exhaustion, state staleness, accountability gaps, and the need for human checkpoints across an extended timeline."}),e.jsx(t,{title:"Long-Running Sessions",number:"Concept 6.13",children:"A long-running session is one that extends beyond a single interaction window — either in time (hours to days) or in scope (many sub-tasks forming a larger goal). Long-running sessions require explicit state management strategies: checkpointing to survive interruptions, context compression to handle window limits, and human oversight integration to ensure the work remains aligned with the user's evolving intentions."}),e.jsx("p",{children:"Three problems compound over time in long-running sessions. First, the context window fills and must be managed. Second, the world changes — facts that were accurate at session start may no longer be. Third, the agent may drift from the user's intent through accumulated small misinterpretations, each reasonable individually but collectively diverging from the original goal."}),e.jsx(a,{title:"Checkpoint, Verify, Continue",number:"Principle 6.6",children:"Long-running sessions should include regular checkpoints where the agent surfaces its understanding of the current state, confirms alignment with the user's goal, and validates that the world has not changed in ways that affect the plan. Checkpoints prevent the compounding of small errors into large failures across extended timelines."}),e.jsx(n,{type:"tip",title:"Intent Drift",children:`Over a long session, a user's intent may legitimately evolve. They start wanting X, but as the work proceeds they realize they need Y. An agent that treats the original goal as immutable will deliver X perfectly when the user now wants Y. Regular intent checks — "Is this still what you're looking for?" — prevent wasted effort and keep the agent aligned with the user's current goal, not their initial one.`}),e.jsx(i,{title:"Long-Running Sessions Practice",exercises:[{id:"e6-13-1",difficulty:"beginner",question:"A research agent is tasked with a project expected to take three days. What types of external state might become stale during that time, and how should the agent handle each?",hint:"Think about data sources the agent relies on and how quickly they change.",solution:"Stale risks: (1) Web sources used in research may be updated — re-fetch when citing, especially for rapidly changing topics. (2) Access permissions may change — re-validate before each write action. (3) The user's goals may evolve — check alignment at each major milestone. (4) Dependent external systems (APIs, databases) may have schema or behavior changes — test before relying on prior results."},{id:"e6-13-2",difficulty:"intermediate",question:"Design a checkpoint protocol for a long-running coding agent. How often should checkpoints occur, what should they contain, and who should approve them before work continues?",hint:"Balance oversight value against interruption cost.",solution:"Checkpoint frequency: after each self-contained work unit (a feature implemented, a bug fixed) rather than on fixed time intervals. Checkpoint content: summary of work completed, current file state, next planned step, any open decisions requiring human input. Approval: automatic continuation for low-risk steps (reading, drafting). Human approval required before: large refactors, deletions, external API calls, or any action flagged as high-consequence. Display checkpoints in a sidebar so the user can review without interrupting the agent."},{id:"e6-13-3",difficulty:"advanced",question:"A long-running agent has been working for two days when the user changes a key requirement that invalidates 40% of the work done so far. Design the strategy for handling this gracefully — what is assessed, what is discarded, and how is the path forward determined?",hint:"Think about impact analysis, recovery cost estimation, and replanning.",solution:"Step 1: Impact analysis — map the changed requirement to the affected work units. Tag each as: (a) unaffected (keep), (b) partially affected (modify), (c) fully invalidated (discard). Step 2: Surface the impact to the user with an estimate of recovery cost before taking any action. Step 3: Get user confirmation that the new requirement justifies the rework. Step 4: Archive invalidated work (do not delete — it may contain reusable elements). Step 5: Replan from the earliest affected checkpoint. Do not restart from zero — preserved work units are the foundation of the new plan. Step 6: Establish a revised goal statement in the persistent state block to prevent re-drift."}]})]})}const W=Object.freeze(Object.defineProperty({__proto__:null,default:v},Symbol.toStringTag,{value:"Module"}));export{j as a,T as b,A as c,S as d,q as e,C as f,I as g,M as h,P as i,D as j,_ as k,z as l,W as m,k as s};
